int k_strcmp(const char* s1, const char* s2) { while (*s1 && (*s1 == *s2)) { s1++; s2++; } return *(const unsigned char*)s1 - *(const unsigned char*)s2; }
void k_memcpy(void* dest, const void* src, uint32_t count) { uint8_t* d = (uint8_t*)dest; const uint8_t* s = (const uint8_t*)src; while (count--) *d++ = *s++; }
void k_strcpy(char* dest, const char* src) { while ((*dest++ = *src++)); }

static inline uint8_t inb(uint16_t port) { uint8_t ret; __asm__ volatile("inb %w1, %b0" : "=a"(ret) : "Nd"(port)); return ret; }
static inline void outb(uint16_t port, uint8_t val) { __asm__ volatile("outb %b0, %w1" : : "a"(val), "Nd"(port)); }

