void draw_real_char(char c, int x, int y, uint32_t color) {
    if (c < 32 || c > 126) return;
    int idx = c - 32; uint32_t c_hex = get_color(color);
    for (int i=0; i<8; i++) for (int j=0; j<8; j++) if (font8x8[idx][i] & (1<<(7-j))) if((y+i)<768 && (x+j)<1024) double_buffer[(y+i)*1024 + (x+j)] = c_hex;
}
void draw_real_string(const char* s, int x, int y, uint32_t color) { while(*s) { draw_real_char(*s, x, y, color); x += 8; s++; } }
void draw_real_rectangle(int w, int h, uint32_t color, int x, int y, int id) {
    if(obj_count < 50 && id > 0) { objects[obj_count].id=id; objects[obj_count].x=x; objects[obj_count].y=y; objects[obj_count].w=w; objects[obj_count].h=h; obj_count++; }
    uint32_t c_hex = get_color(color);
    for(int i=0; i<h; i++) for(int j=0; j<w; j++) if((y+i)<768 && (x+j)<1024) double_buffer[(y+i)*1024 + (x+j)] = c_hex;
}

void draw_image_array(const uint32_t* img_data, int w, int h, int start_x, int start_y) {
    for(int y=0; y<768; y++) {
        for(int x=0; x<1024; x++) {
            double_buffer[y*1024 + x] = img_data[y*1024 + x];
        }
    }
}

void mouse_wait(uint8_t a_type) { uint32_t timeout=100000; if(a_type==0) { while(timeout--) if((inb(0x64)&1)==1) return; } else { while(timeout--) if((inb(0x64)&2)==0) return; } }
void mouse_write(uint8_t a_write) { mouse_wait(1); outb(0x64, 0xD4); mouse_wait(1); outb(0x60, a_write); }
void init_hardware_mouse() { uint8_t s; mouse_wait(1); outb(0x64, 0xA8); mouse_wait(1); outb(0x64, 0x20); mouse_wait(0); s=(inb(0x60)|2); mouse_wait(1); outb(0x64, 0x60); mouse_wait(1); outb(0x60, s); mouse_write(0xF4); inb(0x60); }
char kbd_map[128] = { 0,27,'1','2','3','4','5','6','7','8','9','0','-','=','\b','\t','q','w','e','r','t','y','u','i','o','p','[',']','\n',0,'a','s','d','f','g','h','j','k','l',';','\'','`',0,'\\','z','x','c','v','b','n','m',',','.','/',0,'*',0,' ' };
void handle_keyboard() { uint8_t s = inb(0x64); if(s&1 && !(s&0x20)) { uint8_t scan = inb(0x60); if(!(scan&0x80)) { char key = kbd_map[scan]; if(key=='\n') { input_buffer[input_len]=0; if(k_strcmp(input_buffer, "cli")==0) terminal_active=1; else if(k_strcmp(input_buffer, "gui")==0) terminal_active=0; input_len=0; } else if(key>0 && input_len<30) input_buffer[input_len++]=key; } } }

void update_hardware_mouse() {
    uint8_t s = inb(0x64); if(!(s&1) || !(s&0x20)) return; uint8_t val = inb(0x60);
    switch(mouse_cycle) { case 0: if(val&0x08) { mouse_byte[0]=val; mouse_cycle++; } break; case 1: mouse_byte[1]=val; mouse_cycle++; break; case 2: mouse_byte[2]=val; mouse_cycle=0; mouse_x += (int8_t)mouse_byte[1]; mouse_y -= (int8_t)mouse_byte[2]; if(mouse_x<0) mouse_x=0; if(mouse_x>1016) mouse_x=1016; if(mouse_y<0) mouse_y=0; if(mouse_y>760) mouse_y=760;
    if (mouse_byte[0] & 1) {
        if (mouse_was_clicked == 0) {
            for (int i = 0; i < obj_count; i++) {
                if (mouse_x >= objects[i].x && mouse_x <= (objects[i].x + objects[i].w) && mouse_y >= objects[i].y && mouse_y <= (objects[i].y + objects[i].h)) {
                    clicked_object_id = objects[i].id;
                }
            }
            mouse_was_clicked = 1;
        }
    } else { mouse_was_clicked = 0; }
    break; }
}

void whale_kernel_main(uint32_t magic, uint32_t mbd) {
    if (magic != 0x2BADB002) return;
    uint32_t fb_addr = *(((uint32_t*)(mbd + 88)));
    vga = (volatile uint32_t*)fb_addr;

    uint32_t* syscall_table = (uint32_t*)0x5000;
    syscall_table[0] = (uint32_t)&draw_real_rectangle;
    syscall_table[1] = (uint32_t)&draw_real_string;

    char app_registry[2][32];
    k_strcpy(app_registry[0], "Calculadora");
    k_strcpy(app_registry[1], "Editor");
    while (1) {
        handle_keyboard();
        update_hardware_mouse();
        obj_count = 0;

        if (!terminal_active) {
            draw_image_array(img_0, 1024, 768, 0, 0);
        } else {
            for (int i = 0; i < 786432; i++) double_buffer[i] = 0xFF000000;
        }

        if (mouse_x == 512 && mouse_y == 384) init_hardware_mouse();
        if (!terminal_active) draw_real_rectangle(1024, 40, 8, 0, 728, 2);
        if (!terminal_active) draw_real_rectangle(60, 20, 1, 10, 738, 1);
        if (!terminal_active) draw_real_string("START", 20, 744, 15);
        if (clicked_object_id == 1) { menu_open = !menu_open; clicked_object_id = -1; }
        if (menu_open && !terminal_active) {
            draw_real_rectangle(200, 300, 9, 0, 428, -1);
            draw_real_rectangle(200, 20, 1, 0, 428, -1);
            draw_real_string("Montenegro Work", 0 + 10, 428 + 6, 15);
            for (int i = 0; i < 2; i++) {
                draw_real_string(app_registry[i], 0 + 20, 428 + 35 + (i * 25), 15);
                draw_real_rectangle(200 - 40, 20, 8, 0 + 10, 428 + 30 + (i * 25), 300 + i);
            }
        }
        if (!terminal_active) {
            for (int i = 0; i < 2; i++) {
                if (app_open[i]) {
                    int wx = 300 + (i * 40); int wy = 200 + (i * 40);
                    draw_real_rectangle(400, 300, 7, wx, wy, -1);
                    draw_real_rectangle(400, 25, 1, wx, wy, -1);
                    draw_real_string(app_registry[i], wx + 10, wy + 8, 15);
                    draw_real_rectangle(20, 15, 4, wx + 375, wy + 5, 400 + i);
                    draw_real_string("X", wx + 381, wy + 8, 15);
                    if (i == 0) {
                        k_memcpy((void*)0x800000, app_bin_calculadora, app_bin_calculadora_len);
                        void (*run_external_app)() = (void(*)())0x800000;
                        run_external_app();
                    }
                }
            }

            if (clicked_object_id >= 300 && clicked_object_id < 400) { app_open[clicked_object_id - 300] = 1; menu_open = 0; clicked_object_id = -1; }
            if (clicked_object_id >= 400 && clicked_object_id < 500) { app_open[clicked_object_id - 400] = 0; clicked_object_id = -1; }
            clicked_object_id = -1;

            for (int i = 0; i < 8; i++) for (int j = 0; j < 8; j++) if (win_cursor[i][j]) if (mouse_y + i < 768 && mouse_x + j < 1024) double_buffer[(mouse_y + i) * 1024 + (mouse_x + j)] = 0xFFFFFFFF;
            k_memcpy((void*)vga, double_buffer, 1024 * 768 * 4);
        } else {
            draw_real_string("WHALEOS NATIVE CLI", 10, 10, 10);
            draw_real_string("# ", 10, 30, 15);
            for (int n = 0; n < input_len; n++) draw_real_char(input_buffer[n], 26 + (n * 8), 30, 15);
            k_memcpy((void*)vga, double_buffer, 1024 * 768 * 4);
        }
    }
}
